        if rng.random() < 0.6:
            ops.append('change')
            num = rng.randint(1, 12)
            used_numbers.add(num)
            args.append([rng.randint(1, 20), num])
        else:
            ops.append('find')
            if used_numbers and rng.random() < 0.7:
                args.append([rng.choice(sorted(used_numbers))])
            else:
                args.append([rng.randint(1, 15)])
    return [ops, args]

