import heapq


class NumberContainers:
    def __init__(self):
        self.at = {}
        self.heaps = {}
    def change(self, index, number):
        self.at[index] = number
        self.heaps.setdefault(number, [])
        heapq.heappush(self.heaps[number], index)
        return None
    def find(self, number):
        h = self.heaps.get(number)
        if not h:
            return -1
        while h:
            idx = h[0]
            if self.at.get(idx) == number:
                return idx
            heapq.heappop(h)
        return -1

